            return False
        return True
    def drop_piece(self):
        if self.falling_piece:
            if not self.falling_piece.move(0, 1):
                self.lock_piece()
                return True
        return False
    def lock_piece(self):
        if self.falling_piece:
            self.falling_piece.lock()
            self.falling_piece = None
            self.resolve_game_logic()
    def resolve_game_logic(self):
        cleared = self.game_logic.resolve_chains()
        self.score = self.game_logic.score
    def move_piece(self, dx):
        if self.falling_piece:
            self.falling_piece.move(dx, 0)
    def rotate_piece(self, direction):
        if self.falling_piece:
            self.falling_piece.rotate(direction)
    def update(self):
        if self.falling_piece is None and not self.game_over:
            if not self.spawn_new_piece():
                return
        if self.falling_piece:
            current_time = pygame.time.get_ticks()
            if current_time - self.last_drop_time > self.drop_interval:
                self.drop_piece()
                self.last_drop_time = current_time
